lagzoo<-function(x, lag_n)
{

  if(is.zoo(x)==FALSE)
  {
    stop("zoo objects for lagzoo, please")
  }
  if(ncol(x)==1)
  {
    y<-x
  t<-time(x)
  n<-length(t)

  y[(lag_n+1):n]<-x[1:(n-lag_n)]
  y[1:lag_n]<-NA
  return(y)
  }
  else
  {
    y<-x
    n<-nrow(x)
    y[(lag_n+1):n,]<-x[1:(n-lag_n),]
